import{_ as a,c as t,o as i,ak as r,am as s}from"./chunks/framework.B95DSy-a.js";const p=JSON.parse('{"title":"AireFrame Release Notes","description":"","frontmatter":{},"headers":[],"relativePath":"aireblock-releases/aireframe-v2-45-0.md","filePath":"aireblock-releases/aireframe-v2-45-0.md","lastUpdated":1773760416000}'),o={name:"aireblock-releases/aireframe-v2-45-0.md"};function l(n,e,c,h,u,d){return i(),t("div",null,[...e[0]||(e[0]=[r('<h1 id="aireframe-release-notes" tabindex="-1"><span class="fsc-product"><img src="'+s+'"> AireFrame Release Notes</span> <a class="header-anchor" href="#aireframe-release-notes" aria-label="Permalink to “AireFrame Release Notes”">​</a></h1><blockquote><p><strong>Version:</strong> 2.45.0<br><strong>Release Date:</strong> 25 March 2026</p></blockquote><h2 id="summary-of-changes" tabindex="-1">Summary of Changes <a class="header-anchor" href="#summary-of-changes" aria-label="Permalink to “Summary of Changes”">​</a></h2><h4 id="✨-new-features" tabindex="-1">✨ New Features <a class="header-anchor" href="#✨-new-features" aria-label="Permalink to “✨ New Features”">​</a></h4><ul><li>Themed Login Page (FRAME-2206)</li><li>Form Close Confirmation on Panel Dismiss (FRAME-2478)</li></ul><h4 id="⚡-improvements" tabindex="-1">⚡ Improvements <a class="header-anchor" href="#⚡-improvements" aria-label="Permalink to “⚡ Improvements”">​</a></h4><ul><li>Clear Subject Avatar to Default (FRAME-1572)</li><li>Automatic Image Compression for Subject Avatars (FRAME-1577)</li></ul><h4 id="🐞-bug-fixes" tabindex="-1">🐞 Bug Fixes <a class="header-anchor" href="#🐞-bug-fixes" aria-label="Permalink to “🐞 Bug Fixes”">​</a></h4><ul><li>Structure Tree Updates Without Page Refresh (FRAME-2404)</li><li>Large Text Values Now Stored Correctly in Cache (FRAME-2462)</li><li>Subject List Loading Reliability for Large Datasets (FRAME-2489)</li><li>Multiple-Value Custom Field Filtering (FRAME-2495)</li></ul><hr><h1 id="detailed-changes" tabindex="-1">Detailed Changes <a class="header-anchor" href="#detailed-changes" aria-label="Permalink to “Detailed Changes”">​</a></h1><h3 id="✨-new-features-1" tabindex="-1">✨ New Features <a class="header-anchor" href="#✨-new-features-1" aria-label="Permalink to “✨ New Features”">​</a></h3><hr><h4 id="themed-login-page-frame-2206" tabindex="-1">Themed Login Page (FRAME-2206) <a class="header-anchor" href="#themed-login-page-frame-2206" aria-label="Permalink to “Themed Login Page (FRAME-2206)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>The tenanted login page now fully respects the tenant&#39;s configured theme. The logo is rendered at full width with an appropriate maximum height, ensuring branding is displayed correctly and consistently with the rest of the application.</p></div><div class="tip custom-block"><p class="custom-block-title">What this means for you</p><p>When users visit the login page for your tenant, they will now see your organisation&#39;s logo and branding displayed correctly — no more mismatched or oversized logos on the sign-in screen.</p></div><hr><h4 id="form-close-confirmation-on-panel-dismiss-frame-2478" tabindex="-1">Form Close Confirmation on Panel Dismiss (FRAME-2478) <a class="header-anchor" href="#form-close-confirmation-on-panel-dismiss-frame-2478" aria-label="Permalink to “Form Close Confirmation on Panel Dismiss (FRAME-2478)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>AireFrame now sends a <code>close-form</code> postMessage to the AireForms iframe when a user clicks the close icon on the form display panel. This triggers AireForms&#39; built-in close confirmation dialogue, allowing users to confirm or cancel before discarding unsaved changes. Once confirmed, the <code>form-closed</code> event is sent back to AireFrame to handle panel closure.</p></div><div class="tip custom-block"><p class="custom-block-title">What this means for you</p><p>If you close a form panel before saving, you will now be prompted to confirm whether you want to discard your changes. This prevents accidental loss of data when clicking the close button.</p></div><hr><h3 id="⚡-improvements-1" tabindex="-1">⚡ Improvements <a class="header-anchor" href="#⚡-improvements-1" aria-label="Permalink to “⚡ Improvements”">​</a></h3><hr><h4 id="clear-subject-avatar-to-default-frame-1572" tabindex="-1">Clear Subject Avatar to Default (FRAME-1572) <a class="header-anchor" href="#clear-subject-avatar-to-default-frame-1572" aria-label="Permalink to “Clear Subject Avatar to Default (FRAME-1572)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>Users can now remove a previously uploaded subject avatar image and revert it back to the default placeholder. A clear/reset option has been added to the avatar management interface.</p></div><div class="tip custom-block"><p class="custom-block-title">What this means for you</p><p>If a subject has a profile photo that needs to be removed, you can now clear it with a single action and restore the default avatar.</p></div><hr><h4 id="automatic-image-compression-for-subject-avatars-frame-1577" tabindex="-1">Automatic Image Compression for Subject Avatars (FRAME-1577) <a class="header-anchor" href="#automatic-image-compression-for-subject-avatars-frame-1577" aria-label="Permalink to “Automatic Image Compression for Subject Avatars (FRAME-1577)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>AireFrame now automatically compresses uploaded subject avatar images on the fly before storing them. This removes the need for users to manually resize or compress images prior to upload, as the platform handles optimisation internally.</p></div><div class="tip custom-block"><p class="custom-block-title">What this means for you</p><p>You can upload profile photos for subjects without worrying about file size. AireFrame will automatically reduce the image size where needed, keeping the platform running smoothly without any extra steps from you.</p></div><hr><h3 id="🐞-bug-fixes-1" tabindex="-1">🐞 Bug Fixes <a class="header-anchor" href="#🐞-bug-fixes-1" aria-label="Permalink to “🐞 Bug Fixes”">​</a></h3><hr><h4 id="structure-tree-updates-without-page-refresh-frame-2404" tabindex="-1">Structure Tree Updates Without Page Refresh (FRAME-2404) <a class="header-anchor" href="#structure-tree-updates-without-page-refresh-frame-2404" aria-label="Permalink to “Structure Tree Updates Without Page Refresh (FRAME-2404)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>Fixed an issue where newly created structure types or structures were not appearing in the tree view without performing a hard browser refresh. The external state update handling within the headless tree component has been corrected to reflect changes immediately.</p></div><div class="tip custom-block"><p class="custom-block-title">What this means for you</p><p>When you create a new structure type or structure, it will now appear in the list straight away — you no longer need to refresh the page to see your changes take effect.</p></div><hr><h4 id="large-text-values-now-stored-correctly-in-cache-frame-2462" tabindex="-1">Large Text Values Now Stored Correctly in Cache (FRAME-2462) <a class="header-anchor" href="#large-text-values-now-stored-correctly-in-cache-frame-2462" aria-label="Permalink to “Large Text Values Now Stored Correctly in Cache (FRAME-2462)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>Fixed a database error that occurred when attempting to cache text field values exceeding approximately 300 characters. The underlying index has been updated to handle large string values correctly, using a partial index strategy to maintain filtering and sorting performance without hitting database b-tree index size limits.</p></div><div class="tip custom-block"><p class="custom-block-title">What this means for you</p><p>Text fields containing longer content will now save and load correctly without errors. If you were previously experiencing issues with data not appearing or failing to store in subject lists, this fix resolves that problem.</p></div><hr><h4 id="subject-list-loading-reliability-for-large-datasets-frame-2489" tabindex="-1">Subject List Loading Reliability for Large Datasets (FRAME-2489) <a class="header-anchor" href="#subject-list-loading-reliability-for-large-datasets-frame-2489" aria-label="Permalink to “Subject List Loading Reliability for Large Datasets (FRAME-2489)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>Fixed a timeout issue affecting Subject List V2 when populating data for tenants with a very large number of subjects (9,000+). The background data population job has been refactored to process subjects in batches, preventing transaction timeouts and ensuring all subject data is eventually populated. A pending update indicator is shown while batching is in progress.</p></div><div class="tip custom-block"><p class="custom-block-title">What this means for you</p><p>Subject lists will now load reliably even for large organisations with thousands of subjects. If data is still being populated in the background, you will see an indicator letting you know more records are on their way.</p></div><hr><h4 id="multiple-value-custom-field-filtering-frame-2495" tabindex="-1">Multiple-Value Custom Field Filtering (FRAME-2495) <a class="header-anchor" href="#multiple-value-custom-field-filtering-frame-2495" aria-label="Permalink to “Multiple-Value Custom Field Filtering (FRAME-2495)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>Fixed a bug in the subject query API where providing multiple values for the same custom field filter parameter would only apply the first value, ignoring the rest. The fix ensures all supplied values are correctly included in the query using <code>ExactAny</code> matching logic.</p></div><div class="tip custom-block"><p class="custom-block-title">What this means for you</p><p>Filtering subjects by a custom field with multiple possible values will now return all matching subjects correctly. For example, searching for subjects where a field matches either of two values will now return results for both, rather than just the first one specified.</p></div>',48)])])}const f=a(o,[["render",l]]);export{p as __pageData,f as default};
